import{_ as A,o as p,c as r,a4 as n}from"./chunks/framework.ChErgFjV.js";const a="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==",o="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==",s="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==",g="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==",d="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==",C="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==",B="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==",i="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==",h="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==",e="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==",E=JSON.parse('{"title":"锐角三角函数 — 广州中考典型试题与解析","description":"","frontmatter":{"title":"锐角三角函数 — 广州中考典型试题与解析","date":"2026-07-04T00:00:00.000Z","tags":["锐角三角函数","广州中考","解直角三角形","压轴题"]},"headers":[],"relativePath":"math-junior/trigonometry.md","filePath":"math-junior/trigonometry.md","lastUpdated":1783166224000}'),l={name:"math-junior/trigonometry.md"};function c(m,t,D,P,b,R){return p(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="锐角三角函数-—-广州中考典型试题与解析" tabindex="-1">锐角三角函数 — 广州中考典型试题与解析 <a class="header-anchor" href="#锐角三角函数-—-广州中考典型试题与解析" aria-label="Permalink to &quot;锐角三角函数 — 广州中考典型试题与解析&quot;">​</a></h1><blockquote><p>锐角三角函数是广州中考必考内容，常出现在应用题中，分值 6-8 分。</p><p>难度标注：⭐ 基础 | ⭐⭐ 中等 | ⭐⭐⭐ 较难 | ⭐⭐⭐⭐ 压轴</p></blockquote><hr><h2 id="案例-1-特殊角三角函数值计算-⭐" tabindex="-1">案例 1：特殊角三角函数值计算 ⭐ <a class="header-anchor" href="#案例-1-特殊角三角函数值计算-⭐" aria-label="Permalink to &quot;案例 1：特殊角三角函数值计算 ⭐&quot;">​</a></h2><p><img src="'+a+'" alt="案例1示意图"></p><p><strong>【题目】</strong> 求下列各式的值：</p><p>（1）sin30° × cos60° + tan45°</p><p>（2）2sin60° − cos30° + tan60°</p><p><strong>【解析】</strong></p><p>熟记特殊角三角函数值：</p><table tabindex="0"><thead><tr><th>角度</th><th>sin</th><th>cos</th><th>tan</th></tr></thead><tbody><tr><td>30°</td><td>1/2</td><td>√3/2</td><td>√3/3</td></tr><tr><td>45°</td><td>√2/2</td><td>√2/2</td><td>1</td></tr><tr><td>60°</td><td>√3/2</td><td>1/2</td><td>√3</td></tr></tbody></table><p><strong>（1）</strong> sin30° × cos60° + tan45°</p><p>= 1/2 × 1/2 + 1</p><p>= 1/4 + 1 = 5/4</p><p><strong>（2）</strong> 2sin60° − cos30° + tan60°</p><p>= 2 × √3/2 − √3/2 + √3</p><p>= √3 − √3/2 + √3</p><p>= 2√3 − √3/2 = 3√3/2</p><p><strong>答：（1）5/4；（2）3√3/2</strong></p><p><strong>【方法提炼】</strong> 特殊角三角函数值必须熟记。记忆技巧：sin 值从 30° 到 60° 递增（1/2, √2/2, √3/2），cos 值递减（√3/2, √2/2, 1/2），tan30° × tan60° = 1。考试中直接代入计算，注意 √3/3 与 √3 的区分。</p><hr><h2 id="案例-2-直角三角形中求三角函数值-⭐" tabindex="-1">案例 2：直角三角形中求三角函数值 ⭐ <a class="header-anchor" href="#案例-2-直角三角形中求三角函数值-⭐" aria-label="Permalink to &quot;案例 2：直角三角形中求三角函数值 ⭐&quot;">​</a></h2><p><img src="'+o+'" alt="案例2示意图"></p><p><strong>【题目】</strong> 在 Rt▵ABC 中，∠C = 90°，AC = 5，BC = 12，求 sinA、cosA、tanA 的值。</p><p><strong>【解析】</strong></p><p>先求斜边 AB：</p><p>AB = √(AC² + BC²) = √(25 + 144) = √169 = 13</p><p>由三角函数定义：</p><p>sinA = 对边/斜边 = BC/AB = 12/13</p><p>cosA = 邻边/斜边 = AC/AB = 5/13</p><p>tanA = 对边/邻边 = BC/AC = 12/5</p><p>验证：sin²A + cos²A = (12/13)² + (5/13)² = 144/169 + 25/169 = 169/169 = 1 ✓</p><p><strong>答：sinA = 12/13，cosA = 5/13，tanA = 12/5</strong></p><p><strong>【方法提炼】</strong> 已知直角三角形两边求三角函数值：先由勾股定理求第三边，再按定义代入。口诀：sin 对斜、cos 邻斜、tan 对邻。务必验证 sin²A + cos²A = 1。</p><hr><h2 id="案例-3-解直角三角形-仰角俯角-⭐⭐" tabindex="-1">案例 3：解直角三角形（仰角俯角）⭐⭐ <a class="header-anchor" href="#案例-3-解直角三角形-仰角俯角-⭐⭐" aria-label="Permalink to &quot;案例 3：解直角三角形（仰角俯角）⭐⭐&quot;">​</a></h2><p><img src="'+s+'" alt="案例3示意图"></p><p><strong>【题目】</strong> 如图，在地面上的 C 处测得建筑物顶部 A 的仰角为 30°，C 到建筑物底部 B 的距离为 60 m，求建筑物 AB 的高（结果保留根号）。</p><p><strong>【解析】</strong></p><p>在 Rt▵ABC 中，∠B = 90°，∠C = 30°，BC = 60 m。</p><p>tan∠C = AB/BC</p><p>AB = BC × tan30° = 60 × √3/3 = 20√3</p><p><strong>答：建筑物 AB 高 20√3 m</strong></p><p><strong>【方法提炼】</strong> 仰角问题基本模型：已知水平距离和仰角求高度，tan∠ = 对边/邻边。关键：正确识别仰角所在的直角三角形，仰角是水平线与视线的夹角（向上）。</p><hr><h2 id="案例-4-坡度坡角问题-⭐⭐" tabindex="-1">案例 4：坡度坡角问题 ⭐⭐ <a class="header-anchor" href="#案例-4-坡度坡角问题-⭐⭐" aria-label="Permalink to &quot;案例 4：坡度坡角问题 ⭐⭐&quot;">​</a></h2><p><img src="'+g+'" alt="案例4示意图"></p><p><strong>【题目】</strong> 一段坡面的坡角为 30°，水平距离为 10 m。求：</p><p>（1）坡面的铅直高度 h；</p><p>（2）坡面长度 s；</p><p>（3）坡度 i。</p><p><strong>【解析】</strong></p><p>坡角 α = 30°，水平距离 l = 10 m。</p><p><strong>（1）</strong> tanα = h/l</p><p>h = l × tan30° = 10 × √3/3 = 10√3/3 m</p><p><strong>（2）</strong> cosα = l/s</p><p>s = l/cos30° = 10/(√3/2) = 20√3/3 m</p><p>（或 s = √(l² + h²) = √(100 + 100/3) = √(400/3) = 20√3/3）</p><p><strong>（3）</strong> 坡度 i = h/l = tanα = tan30° = √3/3 = 1/√3</p><p>写成 i = 1:√3</p><p><strong>答：（1）h = 10√3/3 m；（2）s = 20√3/3 m；（3）i = 1:√3</strong></p><p><strong>【方法提炼】</strong> 坡度 i = 铅直高度/水平距离 = tanα（坡角）。坡角 α 是坡面与水平面的夹角。注意：坡度是比值（正切值），不是角度。i = 1:n 表示水平距离为铅直高度的 n 倍。</p><hr><h2 id="案例-5-方向角问题-⭐⭐" tabindex="-1">案例 5：方向角问题 ⭐⭐ <a class="header-anchor" href="#案例-5-方向角问题-⭐⭐" aria-label="Permalink to &quot;案例 5：方向角问题 ⭐⭐&quot;">​</a></h2><p><img src="'+d+'" alt="案例5示意图"></p><p><strong>【题目】</strong> 如图，海面上 A、B 两岛相距 100 海里。从 A 岛看 B 岛在北偏东 30° 方向，从 B 岛看 A 岛在南偏西 45° 方向。一艘渔船从 A 岛出发沿正北方向航行，求渔船离 B 岛最近时距 B 岛的距离。</p><p><strong>【解析】</strong></p><p>设渔船沿正北方向航行到 C 处时距 B 最近，则 BC ⊥ AC，即 ∠ACB = 90°。</p><p>在 A 处，B 在北偏东 30° 方向，即 ∠BAC = 30°（正北方向与 AB 的夹角）。</p><p>在 Rt▵ABC 中，∠ACB = 90°，∠BAC = 30°，AB = 100。</p><p>BC = AB × sin∠BAC = 100 × sin30° = 100 × 1/2 = 50</p><p><strong>答：渔船离 B 岛最近距离为 50 海里</strong></p><p><strong>【方法提炼】</strong> 方向角问题：北偏东 α 表示从正北方向顺时针转 α 度。求最短距离即作垂线段。关键是把方向角转化为三角形内角。注意：方位角是从正北顺时针量到目标方向线的角。</p><hr><h2 id="案例-6-仰角俯角综合-建筑物高度-⭐⭐⭐" tabindex="-1">案例 6：仰角俯角综合（建筑物高度）⭐⭐⭐ <a class="header-anchor" href="#案例-6-仰角俯角综合-建筑物高度-⭐⭐⭐" aria-label="Permalink to &quot;案例 6：仰角俯角综合（建筑物高度）⭐⭐⭐&quot;">​</a></h2><p><img src="'+C+'" alt="案例6示意图"></p><p><strong>【题目】</strong> 如图，建筑物 AB 旁有一斜坡，在坡底 C 处测得建筑物顶部 A 的仰角为 30°，在坡顶 D 处测得 A 的仰角为 45°。已知 C、D 在同一水平面上，CD = 40 m，求建筑物 AB 的高度（结果保留根号）。</p><p><strong>【解析】</strong></p><p>设 AB = h m。</p><p>在 Rt▵ABD 中，∠ADB = 45°，</p><p>BD = AB/tan45° = h/1 = h</p><p>在 Rt▵ABC 中，∠ACB = 30°，</p><p>BC = AB/tan30° = h/(√3/3) = h × 3/√3 = √3h</p><p>由 BC − BD = CD：</p><p>√3h − h = 40</p><p>h(√3 − 1) = 40</p><p>h = 40/(√3 − 1) = 40(√3 + 1)/((√3 − 1)(√3 + 1)) = 40(√3 + 1)/(3 − 1) = 40(√3 + 1)/2 = 20(√3 + 1)</p><p><strong>答：建筑物 AB 高 20(√3 + 1) m</strong></p><p><strong>【方法提炼】</strong> 双仰角求高度模型：设高为 h，分别用 tan 表示两个水平距离，再利用两观测点的水平距离差列方程。分母有理化是常见化简步骤。推广：若两观测点在异侧（建筑物两侧），则 BC + BD = CD。</p><hr><h2 id="案例-7-航海问题-⭐⭐⭐" tabindex="-1">案例 7：航海问题 ⭐⭐⭐ <a class="header-anchor" href="#案例-7-航海问题-⭐⭐⭐" aria-label="Permalink to &quot;案例 7：航海问题 ⭐⭐⭐&quot;">​</a></h2><p><img src="'+B+'" alt="案例7示意图"></p><p><strong>【题目】</strong> 如图，一艘轮船在 B 处观测灯塔 A 在北偏东 30° 方向。轮船沿北偏东 75° 方向航行 10 海里到达 C 处，此时观测灯塔 A 在正西方向。求灯塔 A 到航线 BC 的距离。</p><p><strong>【解析】</strong></p><p>建立坐标系分析角度：</p><p>B 处看 A 在北偏东 30°，即 ∠NBA = 30°（N 为正北方向）。</p><p>轮船沿北偏东 75° 航行，即航线 BC 与正北方向夹角 75°。</p><p>∠ABC = 75° − 30° = 45°（航线方向与 BA 方向的夹角）。</p><p>C 处看 A 在正西方向，即 CA 方向为正西。</p><p>航线 BC 方向为北偏东 75°，正西方向为西偏南 90° 与北偏东 75° 的夹角：</p><p>∠BCA = 180° − 75° − 45° = 60°</p><p>（验证：三角形内角和 = 45° + 60° + 75° = 180° ✓）</p><p>在 ▵ABC 中，∠ABC = 45°，∠BCA = 60°，BC = 10。</p><p>作 AD ⊥ BC 于 D，设 AD = h。</p><p>在 Rt▵ABD 中，∠ABD = 45°，BD = h/tan45° = h。</p><p>在 Rt▵ACD 中，∠ACD = 60°，CD = h/tan60° = h/√3 = √3h/3。</p><p>BD + CD = BC：h + √3h/3 = 10</p><p>h(1 + √3/3) = 10</p><p>h(3 + √3)/3 = 10</p><p>h = 30/(3 + √3) = 30(3 − √3)/((3 + √3)(3 − √3)) = 30(3 − √3)/(9 − 3) = 30(3 − √3)/6 = 5(3 − √3)</p><p><strong>答：灯塔 A 到航线 BC 的距离为 5(3 − √3) 海里</strong></p><p><strong>【方法提炼】</strong> 航海问题核心：将方向角转化为三角形内角。步骤：(1) 标注所有方向角；(2) 计算航线与观测线的夹角；(3) 用正弦定理或作高求解。注意方向角与三角形内角的转化关系。</p><hr><h2 id="案例-8-多直角三角形组合-⭐⭐⭐" tabindex="-1">案例 8：多直角三角形组合 ⭐⭐⭐ <a class="header-anchor" href="#案例-8-多直角三角形组合-⭐⭐⭐" aria-label="Permalink to &quot;案例 8：多直角三角形组合 ⭐⭐⭐&quot;">​</a></h2><p><img src="'+i+'" alt="案例8示意图"></p><p><strong>【题目】</strong> 如图，两栋建筑物 AB 和 CD，AB 高 30 m。从 A 处观测 D 的仰角为 30°，从 B 处观测 C 的俯角为 45°。A、B、C、D 在同一竖直平面内，求建筑物 CD 的高（结果保留根号）。</p><p><strong>【解析】</strong></p><p>设两建筑物之间水平距离为 d m，CD 的高为 h m。</p><p>从 A 看 D 仰角 30°：D 比 A 高出 d × tan30° = √3d/3。</p><p>所以 h = AB + √3d/3 = 30 + √3d/3 …… ˆ1</p><p>从 B 看 C 俯角 45°：C 比 B 低 d × tan45° = d（俯角向下，C 在 B 下方 d 处）。</p><p>所以 C 的高度 = AB − d = 30 − d。</p><p>而 C 的高度即 CD 的高 h = 30 − d …… ˆ2</p><p>由 ˆ1 和 ˆ2：30 + √3d/3 = 30 − d</p><p>√3d/3 = −d</p><p>这说明 C 不能在 B 下方。重新分析：</p><p>从 B 处观测 C 的俯角为 45°，C 是 CD 的底部。如果 C 在地面上，则 C 的高度为 0，俯角应更大。题目说俯角 45°，说明 C 的高度不为 0。</p><p>重新理解：从 B 看 C（CD 的底部），俯角 45°。</p><p>C 的高度 = AB − d × tan45° = 30 − d。</p><p>CD 的高 h，从 A 看 D（CD 顶部）仰角 30°：</p><p>D 的高度 = AB + d × tan30° = 30 + √3d/3。</p><p>h = D 的高度 − C 的高度 = (30 + √3d/3) − (30 − d) = √3d/3 + d = (√3 + 3)d/3</p><p>但 C 的高度 30 − d ≥ 0，d ≤ 30。</p><p>还需一个条件来定 d。题目未给出更多条件，但 h 的表达式中含 d。</p><p>重新审题：从 B 看 C 俯角 45°，C 为建筑物 CD 的底部。如果两建筑物底部在同一水平面上，则 C 的高度为 0。</p><p>从 B（高 30 m）看地面上的 C，俯角 45°：</p><p>d = 30/tan45° = 30 m。</p><p>从 A（高 30 m）看 D 仰角 30°：</p><p>D 比 A 高 √3d/3 = √3 × 30/3 = 10√3 m。</p><p>h = 30 + 10√3 m。</p><p><strong>答：建筑物 CD 高 (30 + 10√3) m</strong></p><p><strong>【方法提炼】</strong> 多建筑物高度问题：分别以每个观测点为基准，用仰角/俯角建立高度关系。关键：俯角向下时目标低于观测点，仰角向上时目标高于观测点。同一水平面上的底部高度为 0 是隐含条件。</p><hr><h2 id="案例-9-三角函数与圆综合-⭐⭐⭐⭐" tabindex="-1">案例 9：三角函数与圆综合 ⭐⭐⭐⭐ <a class="header-anchor" href="#案例-9-三角函数与圆综合-⭐⭐⭐⭐" aria-label="Permalink to &quot;案例 9：三角函数与圆综合 ⭐⭐⭐⭐&quot;">​</a></h2><p><img src="'+h+'" alt="案例9示意图"></p><p><strong>【题目】</strong> 如图，AB 是 ⊙O 的直径，AB = 10，C 是 ⊙O 上一点，∠BAC = 30°。过 C 作 CD ⊥ AB 于 D。</p><p>（1）求 AC 和 BC 的长；</p><p>（2）求 CD 和 AD 的长；</p><p>（3）求阴影部分（弓形 AC）的面积。</p><p><strong>【解析】</strong></p><p>AB 是直径，∠ACB = 90°（直径所对的圆周角为直角）。</p><p><strong>（1）</strong> 在 Rt▵ABC 中，∠ACB = 90°，∠BAC = 30°，AB = 10。</p><p>BC = AB × sin30° = 10 × 1/2 = 5</p><p>AC = AB × cos30° = 10 × √3/2 = 5√3</p><p><strong>（2）</strong> 在 Rt▵ACD 中，∠ADC = 90°，∠CAD = 30°。</p><p>CD = AC × sin30° = 5√3 × 1/2 = 5√3/2</p><p>AD = AC × cos30° = 5√3 × √3/2 = 15/2</p><p><strong>（3）</strong> 弓形 AC 的面积 = 扇形 OAC 面积 − ▵OAC 面积</p><p>∠AOC = 2×∠ABC = 2 × 60° = 120°（圆心角 = 2 × 圆周角）</p><p>（因 ∠ABC = 180° − 90° − 30° = 60°）</p><p>扇形 OAC 面积 = 120/360 × π × 5² = 25π/3</p><p>▵OAC：OA = OC = 5，∠AOC = 120°</p><p>S▵OAC = 1/2 × OA × OC × sin120° = 1/2 × 5 × 5 × √3/2 = 25√3/4</p><p>弓形面积 = 25π/3 − 25√3/4 = 25(4π − 3√3)/12</p><p><strong>答：（1）AC = 5√3，BC = 5；（2）CD = 5√3/2，AD = 15/2；（3）弓形面积 = 25(4π − 3√3)/12</strong></p><p><strong>【方法提炼】</strong> 圆与三角函数综合的关键桥梁：(1) 直径所对圆周角为 90°，自然构造直角三角形；(2) 圆心角 = 2 × 圆周角；(3) 弓形面积 = 扇形面积 − 三角形面积。垂径定理和圆周角定理是构造直角三角形的常用工具。</p><hr><h2 id="案例-10-三角函数与二次函数综合压轴-⭐⭐⭐⭐" tabindex="-1">案例 10：三角函数与二次函数综合压轴 ⭐⭐⭐⭐ <a class="header-anchor" href="#案例-10-三角函数与二次函数综合压轴-⭐⭐⭐⭐" aria-label="Permalink to &quot;案例 10：三角函数与二次函数综合压轴 ⭐⭐⭐⭐&quot;">​</a></h2><p><img src="'+e+'" alt="案例10示意图"></p><p><strong>【题目】</strong> （广州中考风格压轴）已知抛物线 y = −x² + 2x + 3 与 x 轴交于 A、B 两点（A 在 B 左侧），与 y 轴交于点 C。</p><p>（1）求 A、B、C 的坐标及 tan∠ABC 的值；</p><p>（2）在抛物线上是否存在点 P（第一象限内），使 ∠BCP = 45°？若存在，求点 P 坐标；</p><p>（3）在（1）的条件下，求 ▵BCP 面积的最大值。</p><p><strong>【解析】</strong></p><p><strong>（1）</strong> 令 y = 0：−x² + 2x + 3 = 0，x² − 2x − 3 = 0，(x − 3)(x + 1) = 0。</p><p>A(−1, 0)，B(3, 0)。</p><p>令 x = 0：y = 3。C(0, 3)。</p><p>tan∠ABC：在 Rt▵OBC 中（O 为原点），∠OBC 为 ∠ABC，</p><p>OB = 3，OC = 3。</p><p>tan∠ABC = OC/OB = 3/3 = 1，∠ABC = 45°。</p><p><strong>答：A(−1, 0)，B(3, 0)，C(0, 3)，tan∠ABC = 1</strong></p><p><strong>（2）</strong> ∠ABC = 45°，若 ∠BCP = 45°，则 ∠ABP = ∠ABC + ∠BCP = 45° + 45° = 90° 或 ∠BCP = 45° 在 BC 的另一侧。</p><p><strong>情况一：P 在 BC 上方</strong></p><p>设 BP 与 x 轴正方向夹角为 θ，则 θ = ∠ABC + ∠BCP = 45° + 45° = 90°。</p><p>即 BP ⊥ x 轴，P 的横坐标为 3，P 在抛物线上：</p><p>y = −9 + 6 + 3 = 0，即 P(3, 0) = B，不合题意。</p><p><strong>情况二：∠BCP = 45°，P 在 BC 上方另一侧</strong></p><p>由 ∠ABC = 45°，∠BCP = 45°，在 ▵BCP 中：</p><p>设 BP 方向角为 α（从 x 轴正方向量起），则 α = 180° − ∠ABP。</p><p>BC 方向：从 B(3,0) 到 C(0,3)，方向角 = 135°。</p><p>∠BCP = 45°，CP 方向 = BC 方向 + 45° = 135° + 45° = 180°（指向左）或 135° − 45° = 90°（指向上）。</p><p>CP 方向 90°（竖直向上）：CP 所在直线为 x = 0（即 y 轴），P 在 y 轴上且在抛物线上，x = 0 时 y = 3，即 C(0,3)，不合题意。</p><p>CP 方向 180°（水平向左）：CP 所在直线为 y = 3（过 C(0,3) 水平线），与抛物线交点：</p><p>−x² + 2x + 3 = 3，−x² + 2x = 0，x(−x + 2) = 0</p><p>x = 0（即 C 点）或 x = 2。</p><p>P(2, 3)。</p><p>验证：P(2, 3) 在第一象限 ✓</p><p>BC = √(9 + 9) = 3√2</p><p>BP = √((3−2)² + (0−3)²) = √(1+9) = √10</p><p>CP = √((0−2)² + (3−3)²) = 2</p><p>在 ▵BCP 中，BC = 3√2，CP = 2，BP = √10。</p><p>cos∠BCP = (BC² + CP² − BP²)/(2×BC×CP) = (18 + 4 − 10)/(2 × 3√2 × 2) = 12/(12√2) = √2/2</p><p>∠BCP = 45° ✓</p><p><strong>答：存在，P(2, 3)</strong></p><p><strong>（3）</strong> S▵BCP = 1/2 × BC × CP × sin∠BCP</p><p>= 1/2 × 3√2 × 2 × sin45°</p><p>= 1/2 × 3√2 × 2 × √2/2</p><p>= 1/2 × 3√2 × √2</p><p>= 1/2 × 3 × 2 = 3</p><p><strong>答：▵BCP 面积为 3</strong></p><p><strong>【方法提炼】</strong> 三角函数+二次函数压轴题解题策略：(1) 先求关键点坐标和关键角（本题 ∠ABC = 45° 是突破口）；(2) 角度条件转化方向角，再转化为直线方程，与抛物线联立求交点；(3) 面积公式 S = 1/2×a×b×sinC 是联系三角函数与面积的桥梁。核心：把角度条件转化为方向，方向转化为坐标关系。</p><hr><h2 id="方法总结" tabindex="-1">方法总结 <a class="header-anchor" href="#方法总结" aria-label="Permalink to &quot;方法总结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>题型</th><th>核心方法</th><th>难度</th></tr></thead><tbody><tr><td>特殊角三角函数值</td><td>熟记 30°、45°、60° 的 sin、cos、tan 值</td><td>⭐</td></tr><tr><td>直角三角形求三角函数值</td><td>勾股定理求边，按定义代入，注意对边/邻边/斜边</td><td>⭐</td></tr><tr><td>仰角俯角</td><td>tan∠ = 对边/邻边，正确识别直角三角形</td><td>⭐⭐</td></tr><tr><td>坡度坡角</td><td>坡度 i = tanα（坡角），铅直/水平</td><td>⭐⭐</td></tr><tr><td>方向角</td><td>方向角 → 三角形内角，作垂线求最短距离</td><td>⭐⭐</td></tr><tr><td>双仰角求高度</td><td>设高 h，分别用 tan 表示水平距离，列方程</td><td>⭐⭐⭐</td></tr><tr><td>航海问题</td><td>方向角转化内角，作高或正弦定理求解</td><td>⭐⭐⭐</td></tr><tr><td>多直角三角形组合</td><td>多个直角三角形共享边，逐个求解建立方程组</td><td>⭐⭐⭐</td></tr><tr><td>三角函数与圆</td><td>直径 → 直角三角形，圆心角 = 2×圆周角</td><td>⭐⭐⭐⭐</td></tr><tr><td>三角函数与二次函数</td><td>坐标法 + 角度转方向 + 面积公式 S=1/2×a×b×sinC</td><td>⭐⭐⭐⭐</td></tr></tbody></table><h3 id="锐角三角函数核心公式" tabindex="-1">锐角三角函数核心公式 <a class="header-anchor" href="#锐角三角函数核心公式" aria-label="Permalink to &quot;锐角三角函数核心公式&quot;">​</a></h3><ul><li><strong>定义</strong>：sinA = 对边/斜边，cosA = 邻边/斜边，tanA = 对边/邻边</li><li><strong>恒等式</strong>：sin²A + cos²A = 1，tanA = sinA/cosA</li><li><strong>互余关系</strong>：sinA = cos(90° − A)，cosA = sin(90° − A)</li><li><strong>特殊角</strong>：</li></ul><table tabindex="0"><thead><tr><th>α</th><th>sinα</th><th>cosα</th><th>tanα</th></tr></thead><tbody><tr><td>30°</td><td>1/2</td><td>√3/2</td><td>√3/3</td></tr><tr><td>45°</td><td>√2/2</td><td>√2/2</td><td>1</td></tr><tr><td>60°</td><td>√3/2</td><td>1/2</td><td>√3</td></tr></tbody></table><h3 id="解题通法" tabindex="-1">解题通法 <a class="header-anchor" href="#解题通法" aria-label="Permalink to &quot;解题通法&quot;">​</a></h3><ol><li><strong>画图标注</strong>：将所有已知量（边、角、仰角、俯角、方向角）标注在图上</li><li><strong>构造直角三角形</strong>：作高/垂线，将一般三角形拆分为直角三角形</li><li><strong>选对公式</strong>：已知一角一边求另一边 —— 选含该角的三角函数</li><li><strong>列方程求解</strong>：多个直角三角形共享的边是列方程的桥梁</li><li><strong>检验</strong>：验证 sin²A + cos²A = 1，检验结果的合理性</li></ol>',219)])])}const U=A(l,[["render",c]]);export{E as __pageData,U as default};
